// Gemini devuelve el texto en $json.text (via LLM Chain)
const rawContent = $input.first().json.text;

let analisis;
try {
  // Limpiar posibles backticks que Gemini a veces agrega
  const limpio = rawContent
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();
  analisis = JSON.parse(limpio);
} catch (e) {
  // Fallback seguro si el JSON falla
  analisis = {
    prioridad: 'MEDIA',
    categoria: 'CONSULTA',
    sentimiento: 'NEUTRAL',
    resumen_tecnico: 'Error al parsear análisis IA - revisión manual requerida',
    accion_recomendada: 'Revisar ticket manualmente',
    sla_horas: 24,
    requiere_escalacion: false,
    tags: ['parse-error', 'manual-review'],
    error_parseo: true
  };
}

// Agregar metadatos del nodo anterior
const ctx = $('Crear Contexto').first().json;

analisis.procesado_por = 'gemini-2.0-flash';
analisis.timestamp_analisis = new Date().toISOString();
analisis.ticket_id = ctx.ticket_id;
analisis.id_ticket_interno = ctx.id_ticket_interno;
analisis.email_cliente = ctx.email_cliente;
analisis.nombre_cliente = ctx.nombre_cliente;
analisis.asunto_original = ctx.asunto_original;
analisis.descripcion_original = ctx.descripcion_original;

return [{ json: analisis }];

// Recuperar datos del ticket desde el trigger
const asunto = $('Webhook Nuevo Ticket').first().json.body.asunto
const nombre = $('Webhook Nuevo Ticket').first().json.body.nombre;
const email = $('Webhook Nuevo Ticket').first().json.body.email;
const descripcion = $('Webhook Nuevo Ticket').first().json.body.descripcion;
const canal = $('Webhook Nuevo Ticket').first().json.body.canal || 'web';
const ticketId = $('AIRTABLE - Crear Registro Ticket').first().json.id;
const idTicketInterno = $('AIRTABLE - Crear Registro Ticket').first().json.fields.ID_Ticket || 'TKT-' + Date.now();

return [{
  json: {
    prompt_usuario: `Analiza este ticket de soporte técnico:\n\nAsunto: ${asunto}\nCliente: ${nombre}\nEmail: ${email}\nDescripcion: ${descripcion}\nCanal: ${canal}\nFecha: ${new Date().toISOString()}`,
    ticket_id: ticketId,
    id_ticket_interno: idTicketInterno,
    email_cliente: email,
    nombre_cliente: nombre,
    asunto_original: asunto,
    descripcion_original: descripcion
  }
}];
